return items.map((item) => {
  const row = item.json;
  return {
    json: {
      ticket_id: String(row.id),
      cliente: String(row.customer_name || 'Cliente sem nome'),
      canal: String(row.channel || 'outro'),
      mensagens: String(row.message || ''),
      tecnico: String(row.technician || 'Integracao DB'),
      data_evento: String(row.created_at || new Date().toISOString()),
      metadata: {
        sourceSystem: String($env.SOURCE_SYSTEM || 'db'),
        sourceEntityId: String(row.id),
        tenantId: String($env.TENANT_ID || 'default'),
        ingestionId: `db-${row.id}-${Date.now()}`
      }
    }
  };
});
